mapper.select:
select t0.*,ifnull(t1.`总房间数`,0) totalRoomCount, ifnull(t1.`总房间数`,0)-ifnull(t2.`在租房间数`,0) freeRoomCount from (select * from apartment_info where is_deleted = 0
province_id = #{queryVo.provinceId}
city_id = #{queryVo.cityId}
district_id = #{queryVo.districtId}
) t0 left join (select apartment_id,count(*) 总房间数 from room_info where is_deleted = 0 group by apartment_id) t1 on t0.id = t1.apartment_id left join (select apartment_id,count(*) 在租房间数 from lease_agreement where is_deleted = 0 and `status` in (2,5,7) group by apartment_id) t2 on t1.apartment_id = t2.apartment_id
